2","name":"OpenAI Chat Model1","type":"@n8n/n8n-nodes-langchain.lmChatOpenAi","position":[340,1160],"parameters":{"model":{"__rl":true,"mode":"list","value":"gpt-4o-mini"},"options":{}},"credentials":{"openAiApi":{"id":"4zwP0MSr8zkNvvV9","name":"OpenAi account"}},"typeVersion":1.2},{"id":"1d5c9eb2-b468-4dd2-aa77-d33924fdbb41","name":"Telegram","type":"n8n-nodes-base.telegram","position":[820,120],"webhookId":"44d73068-54dc-458b-a6fb-4b4d10ebed34","parameters":{"text":"=Call summary:\\n{{ $json.output.summary }}\\n\\nFirst name: {{ $json.output.first_name }}\\nLast name: {{ $json.output.last_name }}\\nEmail: {{ $json.output.email }}\\nTelephone: {{ $json.output.telephone }}\\nSummary: {{ $json.output.summary }}\\nDate: {{ $json.output.date }}\\nDateTiem: {{ $json.output.dateTime }}","chatId":"CHAT_ID","additionalFields":{}},"credentials":{"telegramApi":{"id":"rQ5q95W7uKesMDx4","name":"Telegram account Fastewb"}},"typeVersion":1.2},{"id":"5ca696a0-b1d2-45f5-93d6-066654a0c2f6","name":"Google Calendar","type":"n8n-nodes-base.googleCalendar","position":[1860,100],"parameters":{"end":"={{ $json.output.end }}","start":"={{ $json.output.start }}","calendar":{"__rl":true,"mode":"list","value":"info@n3w.it","cachedResultName":"info@n3w.it"},"additionalFields":{"summary":"Event title","description":"Event description"}},"credentials":{"googleCalendarOAuth2Api":{"id":"8RFK3u13g2PJEGa9","name":"Google Calendar account"}},"typeVersion":1.3},{"id":"57fedd6a-94a4-4f58-8179-9fd8ae1d0006","name":"OpenAI Chat Model3","type":"@n8n/n8n-nodes-langchain.lmChatOpenAi","position":[1340,320],"parameters":{"model":{"__rl":true,"mode":"list","value":"gpt-4o-mini"},"options":{}},"credentials":{"openAiApi":{"id":"4zwP0MSr8zkNvvV9","name":"OpenAi account"}},"typeVersion":1.2},{"id":"f3f8a781-eb03-4e99-8512-b926249aabba","name":"Structured Output Parser1","type":"@n8n/n8n-nodes-langchain.outputParserStructured","position":[1640,320],"parameters":{"schemaType":"manual","inputSchema":"{\\n\\t\\"type\\": \\"object\\",\\n\\t\\"properties\\": {\\n\\t\\t\\"start\\": {\\n\\t\\t\\t\\"type\\": \\"string\\"\\n\\t\\t},\\n\\t\\t\\"end\\": {\\n\\t\\t\\t\\"type\\": \\"string\\"\\n\\t\\t}\\n\\t}\\n}"},"typeVersion":1.2},{"id":"f3c416a2-6b42-43cc-aa66-e7d146c1b325","name":"n8n_call","type":"n8n-nodes-base.webhook","position":[-340,120],"webhookId":"b352dd49-d3b3-4e0a-a781-17137f7199c8","parameters":{"path":"b352dd49-d3b3-4e0a-a781-17137f7199c8","options":{},"httpMethod":"POST"},"typeVersion":2},{"id":"2862b10c-77d7-4555-b9ec-86c9c4b9fe7b","name":"Sticky Note","type":"n8n-nodes-base.stickyNote","position":[1080,-1140],"parameters":{"width":1140,"height":920,"content":"# STEP 3 - RETELL AI\\n\\n- Register on [Retell AI](https://retellai.com) (10$ FREE credits)\\n- Create an Agent an set \\"Voice & Language\\" and add your system prompt\\n- In Webhook settings add the \\"Agent Level Webhook URL\\" with the n8n webhook node url called \\"n8n_call\\"\\n- Buy a new phone number with your FREE credits by Twilio Provider and connect it to the created agent\\n- Enter the previously created agency and create the flow as shown in the following image\\n![image](https://i.postimg.cc/brtBkgfH/Retellai-flow.png)\\n- Aggiungere 2 funzioni (una per RAG e una per il Booking) e inserire l'url apposito ricavato dai webhook di n8n \\"n8n_rag_function\\" e \\"n8n_check_available\\"\\n\\n"},"typeVersion":1},{"id":"98de797e-56d8-42b4-85a5-245ae7d086db","name":"Sticky Note1","type":"n8n-nodes-base.stickyNote","position":[-340,-100],"parameters":{"color":5,"width":1220,"content":"# STEP 4\\nIntercept the \\"end call\\" event and get the full call transcript\\n- Add your CHAT_ID in Telegram node"},"typeVersion":1},{"id":"ccf11ce4-3bc4-46bd-a71e-12e59d7a2504","name":"n8n_check_available","type":"n8n-nodes-base.webhook","position":[1120,100],"webhookId":"4dcd68b1-91d3-40bc-8aa6-c681126752b2","parameters":{"path":"4dcd68b1-91d3-40bc-8aa6-c681126752b2","options":{},"httpMethod":"POST","responseMode":"lastNode"},"typeVersion":2},{"id":"ddc50779-c0cf-4862-87b9-e187d1ab19a5","name":"When clicking ‘Test workflow’","type":"n8n-nodes-base.manualTrigger","position":[-400,-940],"parameters":{},"typeVersion":1},{"id":"fd6f36d4-c8b3-4643-8df9-a775d94946d9","name":"Qdrant Vector Store","type":"@n8n/n8n-nodes-langchain.vectorStoreQdrant","position":[580,-820],"parameters":{"mode":"insert","options":{},"qdrantCollection":{"__rl":true,"mode":"id","value":"="}},"credentials":{"qdrantApi":{"id":"iyQ6MQiVaF3VMBmt","name":"QdrantApi account"}},"typeVersion":1},{"id":"3c4f9805-57e7-4662-ab12-8bedc5e5a815","name":"Create collection","type":"n8n-nodes-base.httpRequest","position":[-100,-1080],"parameters":{"url":"https://QDRANTURL/collections/COLLECTION","method":"POST","options":{},"jsonBody":"{\\n  \\"filter\\": {}\\n}","sendBody":true,"sendHeaders":true,"specifyBody":"json","authentication":"genericCredentialType","genericAuthType":"httpHeaderAuth","headerParameters":{"parameters":[{"name":"Content-Type","value":"application/json"}]}},"credentials":{"httpHeaderAuth":{"id":"qhny6r5ql9wwotpn","name":"Qdrant API (Hetzner)"}},"typeVersion":4.2},{"id":"b5fdbd4d-0cc9-4b5c-8aa8-b7fe6fd0f3b4","name":"Refresh collection","type":"n8n-nodes-base.httpRequest","position":[-100,-820],"parameters":{"url":"https://QDRANTURL/collections/COLLECTION/points/delete","method":"POST","options":{},"jsonBody":"{\\n  \\"filter\\": {}\\n}","sendBody":true,"sendHeaders":true,"specifyBody":"json","authentication":"genericCredentialType","genericAuthType":"httpHeaderAuth","headerParameters":{"parameters":[{"name":"Content-Type","value":"application/json"}]}},"credentials":{"httpHeaderAuth":{"id":"qhny6r5ql9wwotpn","name":"Qdrant API (Hetzner)"}},"typeVersion":4.2},{"id":"c2f5ded2-adcb-4c50-95e6-94e54a7c2116","name":"Get folder","type":"n8n-nodes-base.googleDrive","position":[120,-820],"parameters":{"filter":{"driveId":{"__rl":true,"mode":"list","value":"My Drive","cachedResultUrl":"https://drive.google.com/drive